                        <div className="mt-4 space-y-2 pt-2 shrink-0">
                            {(currentSelectedItem.type === 'CONSUMABLE' || currentSelectedItem.type === 'SCROLL') && (
                                <button onClick={handleConsume} className="w-full py-2 bg-emerald-800 hover:bg-emerald-700 text-emerald-100 rounded text-[10px] md:text-sm font-bold transition-all">
                                    {currentSelectedItem.type === 'SCROLL' ? 'Study Scroll' : 'Use Item'}
                                </button>
                            )}
                            {currentSelectedItem.baseValue > 0 && currentSelectedItem.type !== 'KEY_ITEM' && (
                                <button 
                                    onClick={handleQuickSell} 
                                    disabled={currentSelectedItem.isLocked}
                                    className={`w-full py-2 rounded text-[10px] md:text-sm font-bold border transition-all ${currentSelectedItem.isLocked ? 'bg-stone-900 border-stone-800 text-stone-700 cursor-not-allowed' : 'bg-stone-800 hover:bg-red-900/30 text-stone-300 border-stone-700'}`}
                                >
                                    {currentSelectedItem.isLocked ? <span className="flex items-center justify-center gap-1"><Lock className="w-3 h-3" /> Item Locked</span> : `Sell (${Math.floor(currentSelectedItem.baseValue * 0.5)}G)`}
                                </button>
                            )}
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-stone-600 p-4 text-center">
                        <Package className="w-6 h-6 md:w-8 md:h-8 opacity-20 mb-2" />
                        <p className="text-[10px] md:text-xs">Select an item</p>
                    </div>
                )}
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { LayoutGrid, List, Lock, Unlock, Star, Sword, Shield, Coins, Package, Sparkles, Check } from 'lucide-react';
import { InventoryItem } from '../types/inventory';
import { getAssetUrl } from '../utils';
import { useGame } from '../context/GameContext';

const RomanTierOverlay = ({ id, isList = false }: { id: string, isList?: boolean }) => {
    const sizeClasses = isList ? "text-[10px] md:text-lg" : "text-xs md:text-2xl";
    const translateClasses = isList ? "translate-y-0.5" : "translate-y-1 md:translate-y-2";

    if (id === 'scroll_t2') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className={`text-amber-500 font-serif font-black ${sizeClasses} drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] ${translateClasses}`}>II</span></div>;
    if (id === 'scroll_t3') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className={`text-amber-500 font-serif font-black ${sizeClasses} drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] ${translateClasses}`}>III</span></div>;
    if (id === 'scroll_t4') return <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><span className={`text-amber-500 font-serif font-black ${sizeClasses} drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] ${translateClasses}`}>IV</span></div>;
    return null;
};

const AdaptiveItemImage = ({ item, className }: { item: InventoryItem, className?: string }) => {
    const isEquip = item.type === 'EQUIPMENT';
    const folder = isEquip ? 'equipments' : 'materials';
    const baseId = (isEquip && item.equipmentData?.recipeId) 
        ? item.equipmentData.recipeId 
        : item.id;

    const [imgSrc, setImgSrc] = useState(getAssetUrl(`${baseId}.png`, folder));

    useEffect(() => {
        setImgSrc(getAssetUrl(`${baseId}.png`, folder));
    }, [baseId, folder]);

    const handleImgError = () => {
        const fallbackPath = item.image || item.equipmentData?.image;
        if (fallbackPath && imgSrc !== getAssetUrl(fallbackPath, folder)) {
            setImgSrc(getAssetUrl(fallbackPath, folder));
        }
    };

    return <img src={imgSrc} onError={handleImgError} className={className} />;
};

interface ItemSelectorListProps {
    items: (InventoryItem & { isSelected?: boolean })[];
    onSelect: (item: InventoryItem) => void;
    onToggleLock: (itemId: string) => void;
    selectedItemId?: string | null;
    customerMarkup?: number;
    emptyMessage?: string;
}

export const ItemSelectorList: React.FC<ItemSelectorListProps> = ({ 
    items, 
    onSelect, 
    onToggleLock, 
    selectedItemId,
    customerMarkup = 1.0,
    emptyMessage = "No items available."
}) => {
    const { state, actions } = useGame();

    // Debug Logging
    useEffect(() => {
        console.group('[ItemSelectorList] Render Debug');
        console.log('Item count:', items.length);
        if (items.length > 0) {
            console.table(items.map(i => ({ name: i.name, type: i.type, id: i.id })));
        } else {
            console.warn('List is empty. Filter might be too restrictive.');
        }
        console.groupEnd();
    }, [items]);

    // Safety check for older save data without settings
    const viewMode = state.settings?.inventoryViewMode || 'LIST';

    const setViewMode = (mode: 'GRID' | 'LIST') => {
        if (actions.updateSettings) {
            actions.updateSettings({ inventoryViewMode: mode });
        }
    };

    const getQualityLabel = (q: number): string => {
        if (q >= 110) return 'Masterwork';
        if (q >= 100) return 'Pristine';
        if (q >= 90) return 'Superior';
        if (q >= 80) return 'Fine';
        if (q >= 70) return 'Standard';
        if (q >= 60) return 'Rustic';
        return 'Crude';
    };

    const getRarityColor = (rarity?: string) => {
        switch (rarity) {
            case 'Legendary': return 'text-amber-100 border-amber-400 bg-amber-600 shadow-[0_0_10px_rgba(245,158,11,0.4)]';
            case 'Epic': return 'text-purple-100 border-purple-400 bg-purple-600 shadow-[0_0_10px_rgba(168,85,247,0.4)]';
            case 'Rare': return 'text-blue-100 border-blue-400 bg-blue-600 shadow-[0_0_10px_rgba(59,130,246,0.4)]';
            case 'Uncommon': return 'text-emerald-100 border-emerald-400 bg-emerald-600 shadow-[0_0_10px_rgba(16,185,129,0.4)]';
            default: return 'text-stone-300 border-stone-600 bg-stone-700';
        }
    };

    if (items.length === 0) {
        return (
            <div className="flex-1 flex flex-col items-center justify-center text-stone-700 italic p-12 text-center bg-stone-950/40 rounded-2xl border border-stone-900 border-dashed m-4 min-h-[200px]">
                <Package className="w-12 h-12 opacity-10 mb-2" />
                <p className="text-sm">{emptyMessage}</p>
            </div>
        );
    }

    return (
        <div className="flex-1 flex flex-col min-h-[300px] bg-stone-900/50 w-full overflow-hidden">
            <div className="flex justify-end p-2 px-4 gap-2 bg-stone-900 border-b border-white/5 shrink-0">
                <button 
                    onClick={() => setViewMode('GRID')}
                    className={`p-1.5 rounded-lg transition-all ${viewMode === 'GRID' ? 'bg-amber-600 text-white shadow-lg scale-110' : 'bg-stone-800 text-stone-500 hover:text-stone-300'}`}
                    title="Grid View"
                >
                    <LayoutGrid className="w-4 h-4" />
                </button>
                <button 
                    onClick={() => setViewMode('LIST')}
                    className={`p-1.5 rounded-lg transition-all ${viewMode === 'LIST' ? 'bg-amber-600 text-white shadow-lg scale-110' : 'bg-stone-800 text-stone-500 hover:text-stone-300'}`}
                    title="List View"
                >
                    <List className="w-4 h-4" />
                </button>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar p-3 md:p-4 bg-stone-950 shadow-[inset_0_4px_20px_rgba(0,0,0,0.8)]">
                <div className={viewMode === 'GRID' ? 'grid grid-cols-2 xs:grid-cols-3 sm:grid-cols-4 md:grid-cols-5 gap-3 pb-8' : 'flex flex-col gap-2 pb-8'}>
                    {items.map(item => {
                        const isLocked = item.isLocked;
                        const isSelected = selectedItemId === item.id || item.isSelected;
                        const isEquip = item.type === 'EQUIPMENT' && item.equipmentData;
                        const finalPrice = Math.ceil((item.baseValue || 0) * customerMarkup);

                        if (viewMode === 'GRID') {
                            const rarityClasses = getRarityColor(item.equipmentData?.rarity);
                            const stats = item.equipmentData?.stats;
                            const mainAtk = stats ? Math.max(stats.physicalAttack || 0, stats.magicalAttack || 0) : 0;
                            const mainDef = stats ? Math.max(stats.physicalDefense || 0, stats.magicalDefense || 0) : 0;
                            const qualityLabel = isEquip ? getQualityLabel(item.equipmentData!.quality) : '';

                            return (
                                <div key={item.id} className="relative group aspect-square">
                                    <button
                                        onClick={() => !isLocked && onSelect(item)}
                                        disabled={isLocked}
                                        className={`w-full h-full rounded-xl border-2 transition-all flex flex-col items-center justify-center p-1 relative overflow-hidden shadow-2xl ${
                                            isSelected ? 'border-indigo-400 bg-indigo-900/20 ring-2 ring-indigo-500/50 shadow-[0_0_15px_rgba(99,102,241,0.3)]' : 
                                            isLocked ? 'bg-stone-950 border-stone-900 opacity-40 grayscale' : 'bg-stone-800 border-stone-700 hover:border-amber-500 active:scale-95'
                                        }`}
                                    >
                                        <div className="absolute inset-0 bg-gradient-to-br from-white/5 to-transparent pointer-events-none"></div>

                                        <div className="relative">
                                            <AdaptiveItemImage item={item} className="w-16 h-16 md:w-20 md:h-20 object-contain p-1 drop-shadow-[0_0_10px_rgba(0,0,0,0.5)]" />
                                            <RomanTierOverlay id={item.id} />
                                        </div>

                                        <div className="absolute top-1.5 left-1.5 flex flex-col gap-1 pointer-events-none items-start max-w-[85%] z-20">
                                            {isEquip && (
                                                <div className={`px-1.5 py-0.5 rounded text-[7px] font-black uppercase border shadow-md leading-none ${rarityClasses}`}>
                                                    {item.equipmentData!.rarity}
                                                </div>
                                            )}
                                            {item.quantity > 1 && (
                                                <div className="bg-stone-950/90 rounded px-1.5 py-0.5 text-[8px] font-mono font-black text-stone-400 border border-stone-800 shadow-md">
                                                    x{item.quantity}
                                                </div>
                                            )}
                                        </div>

                                        {isSelected && (
                                            <div className="absolute top-1 right-1 bg-indigo-600 rounded-full p-0.5 shadow-lg z-30 animate-pulse">
                                                <Check className="w-3 h-3 text-white" />
                                            </div>
                                        )}

                                        {isEquip && (
                                            <div className="absolute top-[60%] left-1/2 -translate-x-1/2 pointer-events-none z-20">
                                                <div className="bg-black/70 backdrop-blur-sm px-2 py-0.5 rounded-full flex items-center gap-1 border border-white/10 shadow-lg">
                                                    <Sparkles className="w-2 h-2 text-amber-400" />
                                                    <span className="text-[7px] font-black text-amber-200 uppercase whitespace-nowrap tracking-tight">{qualityLabel}</span>
                                                </div>
                                            </div>
                                        )}

                                        <div className="absolute bottom-1 inset-x-1.5 flex justify-between items-end pointer-events-none z-20">
                                            {isEquip ? (
                                                <div className="flex flex-col gap-0.5">
                                                    {mainAtk > 0 && (
                                                        <div className="bg-stone-900/90 px-1.5 rounded flex items-center gap-1 border border-orange-900/50 shadow-md">
                                                            <Sword className="w-2 h-2 text-orange-500" />
                                                            <span className="text-[8px] font-mono font-black text-stone-200">{mainAtk}</span>
                                                        </div>
                                                    )}
                                                    {mainDef > 0 && (
                                                        <div className="bg-stone-900/90 px-1.5 rounded flex items-center gap-1 border border-blue-900/50 shadow-md">
                                                            <Shield className="w-2 h-2 text-blue-400" />
                                                            <span className="text-[8px] font-mono font-black text-stone-200">{mainDef}</span>
                                                        </div>
                                                    )}
                                                </div>
                                            ) : <div />}

                                            <div className="bg-stone-900/95 px-1.5 py-0.5 rounded-md flex items-center gap-0.5 border border-amber-900/40 shadow-xl">
                                                <span className="text-[9px] font-mono font-black text-amber-500">{finalPrice}</span>
                                                <Coins className="w-2.5 h-2.5 text-amber-600" />
                                            </div>
                                        </div>
                                    </button>

                                    <button 
                                        onClick={(e) => { e.stopPropagation(); onToggleLock(item.id); }}
                                        className={`absolute top-1.5 right-1.5 p-1.5 rounded-lg border transition-all z-30 shadow-xl ${isLocked ? 'bg-amber-600 border-amber-400 text-white' : 'bg-stone-900/80 border-stone-700 text-stone-500 opacity-0 group-hover:opacity-100 hover:text-stone-200 hover:bg-stone-800'}`}
                                    >
                                        {isLocked ? <Lock className="w-3.5 h-3.5" /> : <Unlock className="w-3.5 h-3.5" />}
                                    </button>
                                </div>
                            );
                        }

                        return (
                            <div key={item.id} className="relative group shrink-0">
                                <button
                                    onClick={() => !isLocked && onSelect(item)}
                                    disabled={isLocked}
                                    className={`w-full flex items-center gap-3 p-2 md:p-3 rounded-xl border-2 transition-all text-left shadow-lg relative overflow-hidden ${
                                        isSelected ? 'border-indigo-400 bg-indigo-900/20 ring-2 ring-indigo-500/10 shadow-[inset_0_0_10px_rgba(99,102,241,0.1)]' : 
                                        isLocked ? 'bg-stone-950 border-stone-900 opacity-50 grayscale cursor-not-allowed' : 'bg-stone-800 border-stone-700 hover:border-amber-500'
                                    }`}
                                >
                                    <div className="absolute inset-0 bg-gradient-to-r from-white/5 to-transparent pointer-events-none"></div>

                                    <div className="w-10 h-10 md:w-16 md:h-16 bg-stone-950 rounded-lg border border-stone-800 flex items-center justify-center shrink-0 overflow-hidden relative shadow-[inset_0_2px_10px_rgba(0,0,0,0.6)]">
                                        <AdaptiveItemImage item={item} className="w-8 h-8 md:w-12 md:h-12 object-contain drop-shadow-md" />
                                        <RomanTierOverlay id={item.id} isList />
                                        {isLocked && <Lock className="absolute top-0.5 right-0.5 w-2.5 h-2.5 text-amber-500 z-30" />}
                                    </div>

                                    <div className="flex-1 min-w-0">
                                        <div className="flex items-center gap-2">
                                            <span className={`text-[11px] md:text-sm font-black truncate ${isSelected ? 'text-indigo-200' : isLocked ? 'text-stone-500' : 'text-stone-100'}`}>{item.name}</span>
                                            {isEquip && (
                                                <div className={`px-1.5 py-0.5 rounded text-[7px] font-black uppercase border shadow-sm leading-none ${getRarityColor(item.equipmentData?.rarity)}`}>
                                                    {item.equipmentData!.rarity}
                                                </div>
                                            )}
                                            {isSelected && (
                                                <div className="bg-indigo-600 px-1.5 py-0.5 rounded text-[7px] font-black text-white uppercase animate-pulse">In Use</div>
                                            )}
                                        </div>

                                        <div className="flex items-center gap-3 mt-1">
                                            {isEquip ? (
                                                <>
                                                    <div className="flex items-center gap-1">
                                                        <Sparkles className="w-3 h-3 text-amber-500" />
                                                        <span className="text-[9px] font-black text-amber-500 uppercase italic tracking-tight">{getQualityLabel(item.equipmentData!.quality)} Grade</span>
                                                    </div>
                                                    <div className="flex items-center gap-2 text-[8px] font-mono font-bold text-stone-500 border-l border-stone-700 pl-2">
                                                        {(item.equipmentData!.stats.physicalAttack > 0 || item.equipmentData!.stats.magicalAttack > 0) && (
                                                            <span className="flex items-center gap-1"><Sword className="w-2.5 h-2.5" /> {item.equipmentData!.stats.physicalAttack || item.equipmentData!.stats.magicalAttack}</span>
                                                        )}
                                                        {(item.equipmentData!.stats.physicalDefense > 0 || item.equipmentData!.stats.magicalDefense > 0) && (
                                                            <span className="flex items-center gap-1"><Shield className="w-2.5 h-2.5" /> {item.equipmentData!.stats.physicalDefense || item.equipmentData!.stats.magicalDefense}</span>
                                                        )}
                                                    </div>
                                                </>
                                            ) : (
                                                <div className="text-[9px] text-stone-500 font-mono font-bold uppercase tracking-wider">Inventory x{item.quantity}</div>
                                            )}
                                        </div>
                                    </div>

                                    <div className="flex flex-col items-end gap-1 shrink-0 bg-stone-950/50 p-2 rounded-lg border border-white/5">
                                        <div className={`flex items-center gap-1 font-mono font-black text-[10px] md:text-sm ${isSelected ? 'text-indigo-400' : isLocked ? 'text-stone-600' : 'text-emerald-400'}`}>
                                            <Coins className="w-3.5 h-3.5" /> {finalPrice}G
                                        </div>
                                    </div>
                                </button>

                                <button 
                                    onClick={(e) => { e.stopPropagation(); onToggleLock(item.id); }}
                                    className={`absolute top-3 right-3 p-1.5 rounded-lg border transition-all z-30 ${isLocked ? 'bg-amber-600 border-amber-400 text-white shadow-lg' : 'bg-stone-900 border-stone-700 text-stone-500 opacity-0 group-hover:opacity-100 hover:text-stone-200'}`}
                                >
                                    {isLocked ? <Lock className="w-3.5 h-3.5" /> : <Unlock className="w-3.5 h-3.5" />}
                                </button>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
    );
};

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { useGame } from '../../../../context/GameContext';
import { EquipmentCategory, EquipmentItem } from '../../../../types';
import { EQUIPMENT_SUBCATEGORIES, EQUIPMENT_ITEMS } from '../../../../data/equipment';
import { MASTERY_THRESHOLDS } from '../../../../config/mastery-config';
import { materials } from '../../../../data/materials';
import { getSmithingLevel, getUnlockedTier, getEnergyCost } from '../../../../utils/craftingLogic';
import { getAssetUrl } from '../../../../utils';

export const useForge = (onNavigate: (tab: any) => void) => {
  const { state, actions } = useGame();
  const { inventory, stats, isCrafting, craftingMastery, unlockedRecipes, tutorialStep, forgeTemperature, lastForgeTime } = state;
  const { hasFurnace, hasWorkbench, hasResearchTable } = state.forge;

  const [activeCategory, setActiveCategory] = useState<EquipmentCategory>('WEAPON');
  const [selectedItem, setSelectedItem] = useState<EquipmentItem | null>(null);
  const [isPanelOpen, setIsPanelOpen] = useState(true);
  const [isSkillsExpanded, setIsSkillsExpanded] = useState(false);
  const [expandedSubCat, setExpandedSubCat] = useState<string | null>('SWORD');
  const [favorites, setFavorites] = useState<string[]>([]);
  const [isFavExpanded, setIsFavExpanded] = useState(true);
  const [hoveredItem, setHoveredItem] = useState<EquipmentItem | null>(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });
  const [quickCraftProgress, setQuickCraftProgress] = useState<number | null>(null);

  // Timer ref for auto-hiding the tooltip
  const tooltipTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const smithingLevel = getSmithingLevel(stats.smithingExp);
  const workbenchLevel = getSmithingLevel(stats.workbenchExp);
  const unlockedSmithingTier = getUnlockedTier(smithingLevel);
  const unlockedWorkbenchTier = getUnlockedTier(workbenchLevel);

  const getInventoryCount = useCallback((id: string) => {
    return inventory.find(i => i.id === id)?.quantity || 0;
  }, [inventory]);

  const currentResidualTemp = useMemo(() => {
    const GLOBAL_COOLING_RATE_PER_SEC = 5;
    const timeDiffSec = (Date.now() - (lastForgeTime || 0)) / 1000;
    return Math.max(0, (forgeTemperature || 0) - (timeDiffSec * GLOBAL_COOLING_RATE_PER_SEC));
  }, [forgeTemperature, lastForgeTime]);

  const isFuelShortage = useMemo(() => {
    if (!selectedItem || selectedItem.craftingType !== 'FORGE') return false;
    const hasHeat = currentResidualTemp > 0;
    const hasFuel = getInventoryCount('charcoal') > 0;
    const isTutorialForging = tutorialStep === 'START_FORGING_GUIDE';
    return !isTutorialForging && !hasHeat && !hasFuel;
  }, [selectedItem, currentResidualTemp, getInventoryCount, tutorialStep]);

  const canEnterForge = useMemo(() => {
    if (!selectedItem) return false;
    if (selectedItem.craftingType === 'FORGE') {
      const hasHeat = currentResidualTemp > 0;
      const hasFuel = getInventoryCount('charcoal') > 0;
      const isTutorialForging = tutorialStep === 'START_FORGING_GUIDE';
      return hasFurnace && (hasFuel || hasHeat || isTutorialForging);
    }
    return hasWorkbench;
  }, [selectedItem, hasFurnace, hasWorkbench, currentResidualTemp, getInventoryCount, tutorialStep]);

  const requiredEnergy = useMemo(() => {
    if (!selectedItem) return 20;
    const count = craftingMastery[selectedItem.id] || 0;
    return getEnergyCost(selectedItem, count);
  }, [selectedItem, craftingMastery]);

  const extraQuickFuel = useMemo(() => {
    if (!selectedItem) return 0;
    return selectedItem.tier === 1 ? 3 : selectedItem.tier === 2 ? 5 : 8;
  }, [selectedItem]);

  const isQuickFuelShortage = useMemo(() => {
    if (!selectedItem || selectedItem.craftingType !== 'FORGE') return false;
    return getInventoryCount('charcoal') < extraQuickFuel;
  }, [selectedItem, getInventoryCount, extraQuickFuel]);

  const visibleItems = useMemo(() => {
    return EQUIPMENT_ITEMS.filter(item => {
      const isUnlocked = item.unlockedByDefault !== false || unlockedRecipes?.includes(item.id);
      if (!isUnlocked) return false;
      const myTier = item.craftingType === 'FORGE' ? unlockedSmithingTier : unlockedWorkbenchTier;
      if (item.tier > myTier) return false;
      const subCatDef = EQUIPMENT_SUBCATEGORIES.find(sc => sc.id === item.subCategoryId);
      return subCatDef?.categoryId === activeCategory;
    });
  }, [activeCategory, unlockedSmithingTier, unlockedWorkbenchTier, unlockedRecipes]);

  const favoriteItems = useMemo(() => visibleItems.filter(item => favorites.includes(item.id)), [visibleItems, favorites]);

  const groupedItems = useMemo(() => {
    const groups: Record<string, EquipmentItem[]> = {};
    visibleItems.forEach(item => {
      if (!groups[item.subCategoryId]) groups[item.subCategoryId] = [];
      groups[item.subCategoryId].push(item);
    });
    return groups;
  }, [visibleItems]);

  const visibleSubCats = useMemo(() => {
    return EQUIPMENT_SUBCATEGORIES.filter(sc => 
      sc.categoryId === activeCategory && (groupedItems[sc.id]?.length || 0) > 0
    );
  }, [activeCategory, groupedItems]);

  const masteryInfo = useMemo(() => {
    if (!selectedItem) return null;
    const count = craftingMastery[selectedItem.id] || 0;
    let label = "Novice";
    let colorClass = "stroke-stone-500";
    let glowClass = "shadow-[0_0_20px_rgba(120,113,108,0.2)]";
    let progress = 0;

    if (count >= MASTERY_THRESHOLDS.ARTISAN) {
      label = "Artisan";
      colorClass = "stroke-amber-500";
      glowClass = "shadow-[0_0_40px_rgba(245,158,11,0.3)]";
      progress = Math.min(100, ((count - MASTERY_THRESHOLDS.ARTISAN) / 20) * 100);
    } else if (count >= MASTERY_THRESHOLDS.ADEPT) {
      label = "Adept";
      colorClass = "stroke-emerald-500";
      glowClass = "shadow-[0_0_30px_rgba(16,185,129,0.2)]";
      progress = ((count - MASTERY_THRESHOLDS.ADEPT) / (MASTERY_THRESHOLDS.ARTISAN - MASTERY_THRESHOLDS.ADEPT)) * 100;
    } else {
      label = "Novice";
      colorClass = "stroke-stone-400";
      glowClass = "shadow-[0_0_20px_rgba(168,162,158,0.15)]";
      progress = (count / MASTERY_THRESHOLDS.ADEPT) * 100;
    }

    const radius = 46;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (progress / 100) * circumference;

    return { label, colorClass, glowClass, progress, circumference, offset, count };
  }, [selectedItem, craftingMastery]);

  const updateTooltipPosition = useCallback((x: number, y: number) => {
    const viewportW = window.innerWidth;
    const viewportH = window.innerHeight;

    const tooltipWidth = window.innerWidth < 768 ? 160 : 256;
    const tooltipHeight = 180;

    let finalX = x + 15;
    let finalY = y + 15;

    if (finalX + tooltipWidth > viewportW - 10) {
      finalX = x - tooltipWidth - 15;
    }

    if (finalY + tooltipHeight > viewportH - 10) {
      finalY = y - tooltipHeight - 15;
    }

    finalX = Math.max(10, Math.min(finalX, viewportW - tooltipWidth - 10));
    finalY = Math.max(10, Math.min(finalY, viewportH - tooltipHeight - 10));

    setTooltipPos({ x: finalX, y: finalY });
  }, []);

  const handleCategoryChange = useCallback((cat: EquipmentCategory) => {
      setActiveCategory(cat);
  }, []);

  const clearTooltipRef = useCallback(() => {
    if (tooltipTimerRef.current) {
      clearTimeout(tooltipTimerRef.current);
      tooltipTimerRef.current = null;
    }
  }, []);

  const startCrafting = useCallback((e?: React.MouseEvent) => {
    if (!selectedItem) return;
    const isRequirementMet = selectedItem.craftingType === 'FORGE' ? hasFurnace : hasWorkbench;

    if (!isRequirementMet) {
      actions.triggerEvent({
        id: 'NONE',
        title: 'Installation Required',
        description: `Requires ${selectedItem.craftingType === 'FORGE' ? 'Furnace' : 'Workbench'}.`,
        options: [{ label: 'Visit Market', action: () => onNavigate('MARKET') }, { label: 'Stay here', action: () => {} }]
      });
      return;
    }

    const missing = selectedItem.requirements.filter(req => getInventoryCount(req.id) < req.count);
    if (missing.length > 0 || isFuelShortage) {
      if (e) updateTooltipPosition(e.clientX, e.clientY);
      setHoveredItem(selectedItem);

      // Auto hide tooltip after 1 second when triggered by click
      clearTooltipRef();
      tooltipTimerRef.current = setTimeout(() => {
        setHoveredItem(null);
        tooltipTimerRef.current = null;
      }, 1000);
      return;
    }

    const energyCost = getEnergyCost(selectedItem, craftingMastery[selectedItem.id] || 0);
    if (stats.energy < energyCost) {
      actions.triggerEnergyHighlight();
      return;
    }

    actions.startCrafting(selectedItem);
    setIsPanelOpen(false);
  }, [selectedItem, hasFurnace, hasWorkbench, getInventoryCount, stats.energy, craftingMastery, actions, onNavigate, isFuelShortage, updateTooltipPosition, clearTooltipRef]);

  const handleMinigameComplete = useCallback((score: number, bonus?: number) => {
    if (selectedItem) {
      actions.finishCrafting(selectedItem, score, bonus);
      if (tutorialStep === 'START_FORGING_GUIDE' && selectedItem.id === 'sword_bronze_t1') {
        actions.setTutorialStep('CRAFT_RESULT_DIALOG');
      }
    }
    setIsPanelOpen(true);
  }, [selectedItem, actions, tutorialStep]);

  const handleQuickCraft = useCallback((e?: React.MouseEvent) => {
    if (!selectedItem) return;

    const missing = selectedItem.requirements.filter(req => getInventoryCount(req.id) < req.count);
    if (missing.length > 0 || isQuickFuelShortage) {
      if (e) updateTooltipPosition(e.clientX, e.clientY);
      setHoveredItem(selectedItem);

      // Auto hide tooltip after 1 second when triggered by click
      clearTooltipRef();
      tooltipTimerRef.current = setTimeout(() => {
        setHoveredItem(null);
        tooltipTimerRef.current = null;
      }, 1000);
      return;
    }

    const energyCost = getEnergyCost(selectedItem, craftingMastery[selectedItem.id] || 0);
    if (stats.energy < energyCost) {
        actions.triggerEnergyHighlight();
        return;
    }

    setQuickCraftProgress(0);
    const duration = 1500;
    const interval = 30;
    const step = (100 / (duration / interval));

    const timer = setInterval(() => {
      setQuickCraftProgress(prev => {
        if (prev === null || prev >= 100) {
          clearInterval(timer);
          actions.consumeItem('charcoal', extraQuickFuel);
          actions.startCrafting(selectedItem);
          actions.finishCrafting(selectedItem, 80, 0, 0.7);
          return null;
        }
        return prev + step;
      });
    }, interval);
  }, [selectedItem, actions, getInventoryCount, stats.energy, craftingMastery, isQuickFuelShortage, extraQuickFuel, updateTooltipPosition, clearTooltipRef]);

  const handleSelectItem = useCallback((item: EquipmentItem) => {
      setSelectedItem(item);
      if (tutorialStep === 'SELECT_SWORD_GUIDE' && item.id === 'sword_bronze_t1') {
          actions.setTutorialStep('START_FORGING_GUIDE');
      }
  }, [tutorialStep, actions]);

  const handleMouseEnter = useCallback((item: EquipmentItem, e: React.MouseEvent) => {
      clearTooltipRef(); // Manual hover overrides auto-hide
      setHoveredItem(item);
      updateTooltipPosition(e.clientX, e.clientY);
  }, [updateTooltipPosition, clearTooltipRef]);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
      if (hoveredItem) updateTooltipPosition(e.clientX, e.clientY);
  }, [hoveredItem, updateTooltipPosition]);

  const handleMouseLeave = useCallback(() => {
    clearTooltipRef();
    setHoveredItem(null);
  }, [clearTooltipRef]);

  const getItemImageUrl = (item: EquipmentItem) => {
    if (item.image) return getAssetUrl(item.image, 'equipments');
    return getAssetUrl(`${item.id}.png`, 'equipments');
  };

  return {
    state,
    actions,
    isCrafting,
    activeCategory,
    selectedItem,
    isPanelOpen,
    isSkillsExpanded,
    activeCategory,
    expandedSubCat,
    favorites,
    isFavExpanded,
    hoveredItem,
    tooltipPos,
    quickCraftProgress,
    smithingLevel,
    workbenchLevel,
    unlockedSmithingTier,
    unlockedWorkbenchTier,
    visibleSubCats,
    groupedItems,
    favoriteItems,
    canEnterForge,
    isFuelShortage,
    isQuickFuelShortage,
    requiredEnergy: selectedItem ? getEnergyCost(selectedItem, craftingMastery[selectedItem.id] || 0) : 20,
    getInventoryCount,
    masteryInfo,
    getItemImageUrl,
    handlers: {
      setActiveCategory,
      setSelectedItem,
      setIsPanelOpen,
      setIsSkillsExpanded,
      setExpandedSubCat,
      setFavorites,
      setIsFavExpanded,
      setHoveredItem,
      setTooltipPos,
      handleCategoryChange,
      startCrafting,
      handleMinigameComplete,
      handleQuickCraft,
      updateTooltipPosition,
      handleSelectItem,
      handleMouseEnter,
      handleMouseMove,
      handleMouseLeave,
      toggleSubCategory: (id: string) => setExpandedSubCat(prev => prev === id ? null : id),
      toggleFavorite: (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        setFavorites(prev => prev.includes(id) ? prev.filter(f => f !== id) : [...prev, id]);
      }
    }
  };
};

import React, { useState, useEffect, useMemo } from 'react';
import { useGame } from '../../context/GameContext';
import { Sword, Shield, Zap, Brain, Check, Star, ArrowUp, Award, Sparkles, Lock, Activity, Heart, Wind } from 'lucide-react';
import { getAssetUrl } from '../../utils';
import { EquipmentStats } from '../../models/Equipment';
import { EQUIPMENT_ITEMS } from '../../data/equipment';
import { MASTERY_THRESHOLDS } from '../../config/mastery-config';
import { UI_MODAL_LAYOUT } from '../../config/ui-config';

const CraftingResultModal = () => {
    const { state, actions } = useGame();
    const item = state.lastCraftedItem;
    const [animatedProgress, setAnimatedProgress] = useState(0);

    const masteryInfo = useMemo(() => {
        if (!item || !item.equipmentData || !item.equipmentData.recipeId) return null;

        const recipeId = item.equipmentData.recipeId;
        const count = state.craftingMastery[recipeId] || 0;

        let label = "Novice";
        let colorClass = "stroke-stone-400";
        let textClass = "text-stone-400";
        let progress = 0;

        if (count >= MASTERY_THRESHOLDS.ARTISAN) {
            label = "Artisan";
            colorClass = "stroke-amber-500";
            textClass = "text-amber-500";
            progress = Math.min(100, ((count - MASTERY_THRESHOLDS.ARTISAN) / 20) * 100);
        } else if (count >= MASTERY_THRESHOLDS.ADEPT) {
            label = "Adept";
            colorClass = "stroke-emerald-500";
            textClass = "text-emerald-500";
            progress = ((count - MASTERY_THRESHOLDS.ADEPT) / (MASTERY_THRESHOLDS.ARTISAN - MASTERY_THRESHOLDS.ADEPT)) * 100;
        } else {
            label = "Novice";
            colorClass = "stroke-stone-400";
            textClass = "text-stone-400";
            progress = (count / MASTERY_THRESHOLDS.ADEPT) * 100;
        }

        const radius = 46;
        const circumference = 2 * Math.PI * radius;

        return { label, colorClass, textClass, progress, circumference, count };
    }, [item, state.craftingMastery]);

    useEffect(() => {
        if (masteryInfo) {
            setAnimatedProgress(0);
            const timer = setTimeout(() => {
                setAnimatedProgress(masteryInfo.progress);
            }, 100);
            return () => clearTimeout(timer);
        }
    }, [masteryInfo]);

    if (!item || !item.equipmentData || !masteryInfo) return null;

    const data = item.equipmentData;
    const recipe = EQUIPMENT_ITEMS.find(r => r.id === data.recipeId);
    const imageUrl = data.image 
        ? getAssetUrl(data.image, 'equipments') 
        : (data.recipeId 
            ? getAssetUrl(`${recipe?.id}.png`, 'equipments') 
            : getAssetUrl(`${item.id.split('_')[0]}.png`, 'equipments'));

    const getQualityLabel = (q: number): string => {
        if (q >= 110) return "Masterwork";
        if (q >= 100) return "Pristine";
        if (q >= 90) return "Superior";
        if (q >= 80) return "Fine";
        if (q >= 70) return "Standard";
        if (q >= 60) return "Rustic";
        return "Crude";
    };

    const getQualityColor = (q: number): string => {
        if (q >= 110) return 'text-amber-400';
        if (q >= 100) return 'text-yellow-400';
        if (q >= 90) return 'text-emerald-400';
        if (q >= 80) return 'text-blue-400';
        return 'text-stone-400';
    };

    const label = getQualityLabel(data.quality);
    const qColor = getQualityColor(data.quality);

    const isLockedByTutorial = state.tutorialStep === 'CRAFT_RESULT_DIALOG';

    const handleFinalize = () => {
        if (isLockedByTutorial) return;
        if (state.tutorialStep === 'FINALIZE_FORGE_GUIDE') {
            actions.setTutorialStep('SHOP_INTRO_DIALOG');
        }
        actions.dismissCraftingResult();
    };

    const renderStatItem = (icon: React.ReactNode, labelStr: string, statKey: keyof EquipmentStats, value: number, customTagClass?: string) => {
        if (value === undefined || value <= 0) return null;

        const baseValue = recipe?.baseStats?.[statKey] || 0;
        const diff = value - baseValue;
        const isUp = diff > 0;

        return (
            <div className={`bg-stone-950/50 p-2 md:p-3 rounded-xl border transition-all flex justify-between items-center ${isUp ? 'border-amber-600/40 shadow-[inner_0_0_10px_rgba(245,158,11,0.1)]' : 'border-stone-800'} ${customTagClass || ''}`}>
                <span className="text-[7px] md:text-[10px] text-stone-500 font-bold uppercase flex items-center gap-1 md:gap-1.5 pr-1 truncate">
                    {icon} {labelStr}
                </span>
                <div className="flex items-center gap-0.5 shrink-0">
                    <span className={`text-[10px] md:text-sm font-mono font-black ${isUp ? 'text-amber-400' : 'text-stone-200'}`}>{value}</span>
                    {isUp && <ArrowUp className="w-2 h-2 md:w-2.5 md:h-2.5 text-amber-500 animate-bounce" />}
                </div>
            </div>
        );
    };

    const offset = masteryInfo.circumference - (animatedProgress / 100) * masteryInfo.circumference;

    return (
        <div className={`${UI_MODAL_LAYOUT.OVERLAY} ${UI_MODAL_LAYOUT.Z_INDEX.RESULT}`}>
            <div className={`${UI_MODAL_LAYOUT.CONTAINER} border-amber-600 animate-in zoom-in-95 duration-300`}>

                <div className="bg-stone-850 p-3 md:p-6 border-b border-stone-800 flex flex-col items-center text-center shrink-0">

                    <div className="relative mb-2 md:mb-4 group">
                        <div className={`w-20 h-20 md:w-32 md:h-32 bg-stone-900 rounded-full flex items-center justify-center relative z-10 p-2 md:p-3 border border-stone-800/50 shadow-2xl`}>
                            <svg className="absolute inset-0 w-full h-full -rotate-90 pointer-events-none scale-105" viewBox="0 0 100 100">
                                <circle cx="50" cy="50" r="46" stroke="currentColor" strokeWidth="4" fill="transparent" className="text-stone-950/40" />
                                <circle 
                                    cx="50" cy="50" r="46" 
                                    stroke="currentColor" strokeWidth="4" fill="transparent"
                                    strokeDasharray={masteryInfo.circumference}
                                    strokeDashoffset={offset}
                                    strokeLinecap="round"
                                    className={`${masteryInfo.colorClass} transition-all duration-[1000ms] ease-out`}
                                />
                            </svg>

                            <img src={imageUrl} className="w-10 h-10 md:w-20 md:h-20 object-contain drop-shadow-2xl z-20 relative" />

                            <div className={`absolute -bottom-1 -right-1 md:bottom-0 md:right-0 z-30 px-1 md:px-1.5 py-0.5 rounded-full border border-stone-700 bg-stone-900 shadow-xl flex items-center gap-1`}>
                                <Star className={`w-2 h-2 md:w-3 md:h-3 fill-current ${masteryInfo.textClass}`} />
                                <span className={`text-[6px] md:text-[9px] font-black uppercase tracking-tighter ${masteryInfo.textClass}`}>{masteryInfo.label}</span>
                            </div>
                        </div>
                    </div>

                    <h2 className="text-base md:text-2xl font-bold text-stone-100 font-serif leading-tight px-2 truncate w-full">{data.name}</h2>

                    <div className="flex flex-col items-center gap-1 mt-1 md:mt-2">
                        <div className={`px-2 md:px-3 py-0.5 md:py-1 rounded-full bg-stone-950 border border-stone-800 font-black uppercase tracking-widest text-[7px] md:text-[10px] ${qColor} flex items-center gap-1 shadow-inner`}>
                            <Sparkles className="w-2.5 h-2.5 md:w-3.5 md:h-3.5 fill-current" /> {label} Quality
                        </div>
                        <div className="flex items-center gap-1 text-[7px] md:text-[9px] font-black text-stone-500 uppercase tracking-widest">
                            <Award className="w-2 h-2 md:w-2.5 md:h-2.5" /> Mastery: {Math.round(masteryInfo.progress)}%
                        </div>
                    </div>
                </div>

                <div className="p-3 md:p-6 space-y-4 overflow-y-auto flex-1 custom-scrollbar">
                    <p className="text-stone-400 text-[9px] md:text-sm text-center italic leading-tight px-2">"{item.description}"</p>

                    {/* Unified Stats Grid - 2 columns */}
                    <div className="grid grid-cols-2 gap-1.5 md:gap-2">
                        {renderStatItem(<Sword className="w-2.5 h-2.5 text-stone-500" />, "P.Atk", "physicalAttack", data.stats.physicalAttack)}
                        {renderStatItem(<Zap className="w-2.5 h-2.5 text-stone-500" />, "M.Atk", "magicalAttack", data.stats.magicalAttack)}
                        {renderStatItem(<Shield className="w-2.5 h-2.5 text-stone-500" />, "P.Def", "physicalDefense", data.stats.physicalDefense)}
                        {renderStatItem(<Brain className="w-2.5 h-2.5 text-stone-500" />, "M.Def", "magicalDefense", data.stats.magicalDefense)}

                        {/* Bonus Stats in the same grid with color coding */}
                        {renderStatItem(<Activity className="w-2.5 h-2.5 text-orange-400" />, "STR", "str", data.stats.str || 0, "border-orange-500/20 bg-orange-500/10")}
                        {renderStatItem(<Heart className="w-2.5 h-2.5 text-red-400" />, "VIT", "vit", data.stats.vit || 0, "border-red-500/20 bg-red-500/10")}
                        {renderStatItem(<Wind className="w-2.5 h-2.5 text-emerald-400" />, "DEX", "dex", data.stats.dex || 0, "border-emerald-500/20 bg-emerald-500/10")}
                        {renderStatItem(<Brain className="w-2.5 h-2.5 text-blue-400" />, "INT", "int", data.stats.int || 0, "border-blue-500/20 bg-blue-500/10")}
                        {renderStatItem(<Star className="w-2.5 h-2.5 text-pink-400" />, "LUK", "luk", data.stats.luk || 0, "border-pink-500/20 bg-pink-500/10")}
                    </div>
                </div>

                <div className="p-3 md:p-5 border-t border-stone-800 bg-stone-850 shrink-0">
                    <button 
                        onClick={handleFinalize} 
                        disabled={isLockedByTutorial}
                        data-tutorial-id="FINALIZE_BUTTON"
                        className={`w-full py-2.5 md:py-4 font-black rounded-xl shadow-lg flex items-center justify-center gap-2 transition-all text-[10px] md:text-base uppercase tracking-widest border-b-4 ${
                            isLockedByTutorial 
                            ? 'bg-stone-800 text-stone-600 border-stone-900 grayscale cursor-not-allowed' 
                            : 'bg-amber-600 hover:bg-amber-500 text-white border-amber-800 active:scale-95'
                        }`}
                    >
                        {isLockedByTutorial ? (
                            <><Lock className="w-3 h-3 md:w-4 md:h-4" /> Reviewing...</>
                        ) : (
                            <><Check className="w-3 h-3 md:w-4 md:h-4" /> Finalize Forge</>
                        )}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default CraftingResultModal;

import React from 'react';
import { X, Check, Search, Sword, Shield, Zap, Brain, Sparkles, Lock, Info } from 'lucide-react';
import { InventoryItem } from '../../../../types/inventory';
import { ItemSelectorList } from '../../../ItemSelectorList';
import { getAssetUrl } from '../../../../utils';

interface InstanceSelectorPopupProps {
    show: boolean;
    onClose: () => void;
    matchingItems: InventoryItem[];
    selectedInstance: InventoryItem | null;
    onSelect: (item: InventoryItem) => void;
    onSell: (item: InventoryItem) => void;
    onToggleLock: (id: string) => void;
    customerMarkup: number;
}

export const InstanceSelectorPopup: React.FC<InstanceSelectorPopupProps> = ({
    show, onClose, matchingItems, selectedInstance, onSelect, onSell, onToggleLock, customerMarkup
}) => {
    if (!show) return null;

    const getQualityLabel = (q: number): string => {
        if (q >= 110) return 'MASTERWORK';
        if (q >= 100) return 'PRISTINE';
        if (q >= 90) return 'SUPERIOR';
        if (q >= 80) return 'FINE';
        if (q >= 70) return 'STANDARD';
        if (q >= 60) return 'RUSTIC';
        return 'CRUDE';
    };

    const getRarityColor = (rarity?: string) => {
        switch (rarity) {
            case 'Legendary': return 'text-amber-100 border-amber-400 bg-amber-600 shadow-[0_0_10px_rgba(245,158,11,0.4)]';
            case 'Epic': return 'text-purple-100 border-purple-400 bg-purple-600 shadow-[0_0_10px_rgba(168,85,247,0.4)]';
            case 'Rare': return 'text-blue-100 border-blue-400 bg-blue-600 shadow-[0_0_10px_rgba(59,130,246,0.4)]';
            case 'Uncommon': return 'text-emerald-100 border-emerald-400 bg-emerald-600 shadow-[0_0_10px_rgba(16,185,129,0.4)]';
            default: return 'text-stone-300 border-stone-600 bg-stone-700';
        }
    };

    const getInventoryItemImageUrl = (item: InventoryItem) => {
        const isEquip = item.type === 'EQUIPMENT';
        const folder = isEquip ? 'equipments' : 'materials';
        if (isEquip && item.equipmentData) {
            if (item.equipmentData.image) return getAssetUrl(item.equipmentData.image, folder);
            return item.equipmentData.recipeId ? getAssetUrl(`${item.equipmentData.recipeId}.png`, folder) : getAssetUrl(`${item.id.split('_')[0]}.png`, folder);
        }
        return getAssetUrl(`${item.id}.png`, folder);
    };

    return (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-in fade-in duration-300 pointer-events-auto">
            <div className="bg-stone-900 border-2 border-stone-700 rounded-3xl w-full max-w-4xl max-h-[85vh] overflow-hidden flex flex-row shadow-2xl animate-in zoom-in-95 duration-300 relative">
                <div className="flex-1 flex flex-col border-r border-stone-800 bg-stone-925/50 overflow-hidden">
                    <div className="p-4 md:p-6 border-b border-stone-800 flex justify-between items-center bg-stone-900 shrink-0">
                        <div>
                            <h3 className="font-serif font-black text-xl text-stone-100 uppercase tracking-tighter">Select Instance</h3>
                            <p className="text-[10px] text-stone-500 uppercase font-black tracking-widest mt-0.5">Which one will you part with?</p>
                        </div>
                        <button onClick={onClose} className="p-2 hover:bg-stone-800 rounded-full text-stone-500 transition-colors"><X className="w-5 h-5" /></button>
                    </div>
                    <ItemSelectorList 
                        items={matchingItems}
                        onSelect={onSelect}
                        onToggleLock={onToggleLock}
                        customerMarkup={customerMarkup}
                    />

                    <div className="p-4 border-t border-stone-800 bg-stone-900/80 flex justify-end gap-3 shrink-0">
                        <button 
                            onClick={onClose}
                            className="px-6 py-3 rounded-xl bg-stone-800 hover:bg-stone-700 text-stone-400 font-black uppercase text-xs transition-all flex items-center gap-2"
                        >
                            <X className="w-4 h-4" /> Cancel
                        </button>
                        <button 
                            onClick={() => selectedInstance && onSell(selectedInstance)}
                            disabled={!selectedInstance || selectedInstance.isLocked}
                            className={`px-10 py-3 rounded-xl font-black uppercase text-xs transition-all flex items-center gap-2 border-b-4 ${(!selectedInstance || selectedInstance.isLocked) ? 'bg-stone-800 text-stone-600 border-stone-950 grayscale cursor-not-allowed' : 'bg-emerald-600 hover:bg-emerald-500 text-white border-emerald-800 shadow-xl active:scale-95'}`}
                        >
                            <Check className="w-4 h-4" /> Select & Sell
                        </button>
                    </div>
                </div>

                <div className="hidden md:flex w-72 lg:w-96 flex-col bg-stone-900 overflow-hidden">
                    <div className="p-6 border-b border-stone-800 flex items-center gap-3 shrink-0">
                        <div className="text-stone-500"><Info className="w-5 h-5" /></div>
                        <h3 className="font-bold text-stone-400 uppercase tracking-widest text-sm">Item Inspection</h3>
                    </div>
                    <div className="flex-1 p-6 overflow-y-auto custom-scrollbar flex flex-col min-h-0">
                        {selectedInstance ? (
                            <div className="flex flex-col gap-6 animate-in fade-in slide-in-from-right-4 duration-500">
                                <div className="flex flex-col items-center text-center">
                                    <div className={`w-24 h-24 bg-stone-950 rounded-full border-2 flex items-center justify-center mb-3 shadow-2xl relative ${getRarityColor(selectedInstance.equipmentData?.rarity)}`}>
                                        <img src={getInventoryItemImageUrl(selectedInstance)} className={`w-16 h-16 object-contain ${selectedInstance.isLocked ? 'opacity-50 grayscale' : ''}`} />
                                        {selectedInstance.isLocked && (
                                            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-amber-600 p-2 rounded-full border-2 border-stone-900 shadow-xl">
                                                <Lock className="w-6 h-6 text-white" />
                                            </div>
                                        )}
                                    </div>
                                    <h4 className="text-xl font-bold text-amber-500 font-serif leading-none">{selectedInstance.name}</h4>
                                    <div className="flex flex-col items-center gap-1.5 mt-2.5">
                                        <div className={`px-3 py-0.5 rounded-full border text-[9px] font-black uppercase tracking-widest flex items-center gap-1 shadow-sm ${getRarityColor(selectedInstance.equipmentData?.rarity)}`}>
                                            {selectedInstance.equipmentData?.rarity}
                                        </div>
                                        <div className={`px-2 py-0.5 rounded border border-stone-800 bg-stone-950 text-[8px] font-bold uppercase flex items-center gap-1 ${selectedInstance.equipmentData?.quality && selectedInstance.equipmentData.quality >= 100 ? 'text-amber-400' : 'text-stone-500'}`}>
                                            <Sparkles className="w-2.5 h-2.5 fill-current" /> {getQualityLabel(selectedInstance.equipmentData?.quality || 100)} Grade
                                        </div>
                                    </div>
                                </div>

                                {selectedInstance.equipmentData && (
                                    <div className="space-y-4">
                                        <h5 className="text-[10px] font-black text-stone-600 uppercase tracking-widest border-b border-stone-800 pb-1 flex items-center gap-2"><Sword className="w-3 h-3" /> Performance</h5>
                                        <div className="grid grid-cols-2 gap-2">
                                            {[
                                                { label: 'P.ATK', value: selectedInstance.equipmentData.stats.physicalAttack, icon: <Sword className="w-3 h-3 text-orange-500" /> },
                                                { label: 'P.DEF', value: selectedInstance.equipmentData.stats.physicalDefense, icon: <Shield className="w-3 h-3 text-blue-500" /> },
                                                { label: 'M.ATK', value: selectedInstance.equipmentData.stats.magicalAttack, icon: <Zap className="w-3 h-3 text-blue-400" /> },
                                                { label: 'M.DEF', value: selectedInstance.equipmentData.stats.magicalDefense, icon: <Brain className="w-3 h-3 text-purple-400" /> }
                                            ].map(s => (
                                                <div key={s.label} className="bg-stone-950/50 p-2 rounded-lg border border-stone-800 flex justify-between items-center">
                                                    <span className="text-[9px] font-bold text-stone-500 flex items-center gap-1">{s.icon} {s.label}</span>
                                                    <span className="font-mono text-xs font-black text-stone-200">{s.value}</span>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}

                                <div className="mt-auto pt-6">
                                    <div className="flex justify-between items-center px-1 mb-2">
                                        <span className="text-[10px] font-black text-stone-500 uppercase tracking-widest">Offered Price</span>
                                        <span className={`text-2xl font-mono font-black ${selectedInstance.isLocked ? 'text-stone-600' : 'text-emerald-400'}`}>{Math.ceil(selectedInstance.baseValue * customerMarkup)} G</span>
                                    </div>
                                </div>
                            </div>
                        ) : (
                            <div className="flex-1 flex flex-col items-center justify-center text-stone-700 italic text-center p-8 gap-4 opacity-50">
                                <Search className="w-12 h-12" />
                                <p className="text-sm">Select an item to inspect its quality and stats before finalizing the contract.</p>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';
import { SmithingTutorialHandler } from './SmithingTutorialHandler';
import { SMITHING_CONFIG } from '../config/smithing-config';

export interface SmithingSceneData {
  onComplete: (score: number, enhancementCount: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  onTutorialTargetUpdate?: (rect: { x: number, y: number, w: number, h: number } | null) => void;
  onTutorialAction?: (action: 'FIRST_HIT_DONE' | 'CRAFT_FINISHED') => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number | string;
  isTutorial?: boolean;
}

interface Point {
  x: number;
  y: number;
}

type SmithingTool = 'HAMMER' | 'TONGS';

const MAX_TEMP = 1500;
const IDLE_TEMP = 10;

export default class SmithingScene extends Phaser.Scene {
  declare public add: Phaser.GameObjects.GameObjectFactory;
  declare public tweens: Phaser.Tweens.TweenManager;
  declare public scale: Phaser.Scale.ScaleManager;
  declare public cameras: Phaser.Cameras.Scene2D.CameraManager;
  declare public input: Phaser.Input.InputPlugin;
  declare public time: Phaser.Time.Clock;
  declare public events: Phaser.Events.EventEmitter;
  declare public load: Phaser.Loader.LoaderPlugin;
  declare public textures: Phaser.Textures.TextureManager;
  declare public anims: Phaser.Animations.AnimationManager;
  declare public make: Phaser.GameObjects.GameObjectCreator;
  declare public game: Phaser.Game;

  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;

  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private targetOutlineGraphics!: Phaser.GameObjects.Graphics;

  private progressBar!: Phaser.GameObjects.Graphics;
  private progBg!: Phaser.GameObjects.Graphics;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private qualityText!: Phaser.GameObjects.Text;

  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;

  private billetContainer!: Phaser.GameObjects.Container;
  private billetImage?: Phaser.GameObjects.Image;
  private manualControlsContainer!: Phaser.GameObjects.Container;

  private toolSwitcherContainer!: Phaser.GameObjects.Container;
  private hammerBtn!: Phaser.GameObjects.Container;
  private tongsBtn!: Phaser.GameObjects.Container;
  private currentTool: SmithingTool = 'HAMMER';
  private hammerSprite!: Phaser.GameObjects.Image;

  private isRotatingManual = false;
  private isMovingManualX = false;
  private isMovingManualY = false;
  private startPointerPos = { x: 0, y: 0 };
  private startBilletPos = { x: 0, y: 0 };
  private startPointerAngle = 0;
  private startBilletRotation = 0;
  private isSnapped = false;
  private snapTween?: Phaser.Tweens.Tween;

  private hitPoly!: Phaser.Geom.Polygon;
  private spawnPoly!: Phaser.Geom.Polygon; 
  private outlineCache: Map<string, Point[]> = new Map();

  private centerX = 0;
  private centerY = 0;
  private hitX = 0;
  private hitY = 0;

  private viewW = 0;
  private viewH = 0;

  private score = 0;
  private targetScore = 100;
  private combo = 0;
  private lastHitTime = 0;
  private hitCooldown = 200;
  private isFinished = false;
  private isPlaying = false;
  private isReadyToStart = false;

  private currentQuality = 100;
  private perfectCount = 0;
  private enhancementCount = 0; 
  private pinnedTexts: Phaser.GameObjects.Text[] = [];

  private temperature = 0;
  private coolingRate = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';
  private charcoalCount: number | string = 0;

  private startRadius = 180;
  private targetRadius = 45;
  private currentRadius = 180;
  private shrinkDuration = 2000;
  private ringTimer = 0;

  private currentTargetColor = 0xfabf24;
  private currentSpeedMult = 1.0;

  private readonly UI_PAD_TOP = 18;
  private readonly UI_PAD_SIDE = 16; 
  private readonly UI_PAD_BOTTOM = 28;
  private readonly UI_GAP = 18;

  private readonly TEMP_GAUGE_H_MIN = 80;

  private tempBarGraphics!: Phaser.GameObjects.Graphics;
  private tempBgGraphics!: Phaser.GameObjects.Graphics;
  private tempValueText!: Phaser.GameObjects.Text;

  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;
  private bellowsBg!: Phaser.GameObjects.Arc;

  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;
  private isPumping = false;

  private onComplete?: (score: number, enhancementCount: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;
  private onTutorialTargetUpdate?: (rect: { x: number, y: number, w: number, h: number } | null) => void;
  private onTutorialAction?: (action: 'FIRST_HIT_DONE' | 'CRAFT_FINISHED') => void;
  private isTutorial = false;

  private root!: Phaser.GameObjects.Container;

  private isPortrait = false;
  private lastPortrait?: boolean;
  private isRelayouting = false;

  private readonly BILLET_W_ON_ANVIL = 0.80; 
  private readonly BILLET_ANGLE_DEG = -12;

  private readonly SNAP_DIST_THRESHOLD = 25;
  private readonly SNAP_ANGLE_THRESHOLD = Phaser.Math.DegToRad(6);

  private readonly ANVIL_ORIGINAL_W = 1024;
  private readonly ANVIL_ORIGINAL_H = 559;
  private readonly ANVIL_HIT_X = 630;
  private readonly ANVIL_HIT_Y = 140;

  constructor() {
    super('SmithingScene');
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK';
    if (q >= 100) return 'PRISTINE';
    if (q >= 90) return 'SUPERIOR';
    if (q >= 80) return 'FINE';
    if (q >= 70) return 'STANDARD';
    if (q >= 60) return 'RUSTIC';
    return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.onTutorialTargetUpdate = data.onTutorialTargetUpdate;
    this.onTutorialAction = data.onTutorialAction;
    this.isTutorial = !!data.isTutorial;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;
    this.score = 0;
    this.combo = 0;
    this.enhancementCount = 0;
    this.pinnedTexts = [];
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = this.temperature > 0;
    this.currentQuality = 100;
    this.perfectCount = 0;
    this.outlineCache.clear();
    this.currentTool = 'HAMMER';
    this.isSnapped = true;
  }

  preload() {
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('billet_stage_0', getAssetUrl('billet_default.png', 'equipments'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png', 'equipments'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png', 'equipments'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png', 'equipments'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png', 'equipments'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png', 'equipments'));
    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), { frameWidth: 298, frameHeight: 188 });
    this.load.image('icon_hammer', getAssetUrl('hammer.png'));
    this.load.image('icon_tongs', getAssetUrl('tongs.png'));
    this.load.image('hammer_strike', getAssetUrl('hammer.png'));
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;
    this.root = this.add.container(0, 0);
    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map((i) => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }
    this.backgroundTile = this.add.tileSprite(0, 0, 1280, 720, 'tile_forge').setOrigin(0).setDepth(-2).setAlpha(0.7);
    this.root.add(this.backgroundTile);
    this.bgOverlay = this.add.rectangle(0, 0, 1280, 720, 0x000000, 0.4).setOrigin(0).setDepth(-1);
    this.root.add(this.bgOverlay);
    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.root.add(this.anvilImage);

    this.targetOutlineGraphics = this.add.graphics().setDepth(2).setAlpha(0.6);
    this.root.add(this.targetOutlineGraphics);

    this.billetContainer = this.add.container(0, 0).setDepth(3).setAngle(this.BILLET_ANGLE_DEG);

    if (this.textures.exists('billet_stage_0')) {
      this.billetImage = this.add.image(0, 0, 'billet_stage_0').setOrigin(0.5);
      this.billetContainer.add(this.billetImage);
    }
    this.root.add(this.billetContainer);

    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);
    this.root.add([this.targetRing, this.approachRing]);
    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.root.add(this.uiContainer);
    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);
    this.root.add(this.ambientGlow);
    this.flashOverlay = this.add.rectangle(0, 0, 1280, 720, 0xffaa00, 0).setOrigin(0).setDepth(100);
    this.root.add(this.flashOverlay);

    this.hammerSprite = this.add.image(0, 0, 'hammer_strike').setOrigin(0.5, 0.9).setScale(0.5).setAlpha(0).setDepth(30);
    this.root.add(this.hammerSprite);

    this.setupUI();
    this.setupManualControls();
    this.setupToolSwitcher();

    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);
    this.events.once(Phaser.Scenes.Events.SHUTDOWN, () => {
      this.scale.off('resize', this.handleResize, this);
    });
    this.time.delayedCall(80, () => this.handleResize());

    this.setBilletStage(0);

    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
        const x = pointer.x; const y = pointer.y;
        const isBellowsClick = this.isBellowsClick(objs);
        const isHeatUpClick = this.isHeatUpClick(objs);
        const isSwitcherClick = objs.some(obj => obj.parentContainer === this.toolSwitcherContainer || obj === this.toolSwitcherContainer);

        if (isBellowsClick) { this.pumpBellows(); return; }
        if (isHeatUpClick) { this.requestHeatUp(); return; }
        if (isSwitcherClick) return;

        if (!this.isPlaying) { this.handleStartTap(x, y); return; }

        if (this.currentTool === 'HAMMER') {
          if (this.isPointerInHitArea(x, y)) {
            this.handleHammerSwing(x, y);
          } else { 
            const isOnAnvil = this.anvilImage.getBounds().contains(x, y);
            this.handleMiss(x, y, isOnAnvil ? 'STRUCK ANVIL' : 'MISS'); 
          }
        }
      }, this
    );

    this.input.on('pointermove', (pointer: Phaser.Input.Pointer) => {
        if (this.isSnapped) return;
        if (this.isRotatingManual) {
            const currentAngle = Phaser.Math.Angle.Between(this.billetContainer.x, this.billetContainer.y, pointer.x, pointer.y);
            const delta = currentAngle - this.startPointerAngle;
            this.billetContainer.rotation = this.startBilletRotation + delta;
            this.checkMagnetSnap();
        } 
        else if (this.isMovingManualX) {
            const dx = pointer.x - this.startPointerPos.x;
            this.billetContainer.x = this.startBilletPos.x + dx;
            this.checkMagnetSnap();
        }
        else if (this.isMovingManualY) {
            const dy = pointer.y - this.startPointerPos.y;
            this.billetContainer.y = this.startBilletPos.y + dy;
            this.checkMagnetSnap();
        }
        if (this.isRotatingManual || this.isMovingManualX || this.isMovingManualY) {
            this.rebuildHitPoly();
            if (this.currentTool === 'TONGS') {
                this.drawTargetGuidelineFixed();
            }
        }
    });

    this.input.on('pointerup', () => {
        this.isRotatingManual = false;
        this.isMovingManualX = false;
        this.isMovingManualY = false;
    });

    this.switchTool('HAMMER');
  }

  private triggerHammerAnimation(x: number, y: number) {
    this.hammerSprite.setAlpha(1).setPosition(x + 50, y - 150).setAngle(15).setScale(0.5 * this.uiScale);
    this.tweens.add({
      targets: this.hammerSprite,
      x: x,
      y: y + 20,
      angle: -25,
      duration: 100,
      ease: 'Cubic.in',
      onComplete: () => {
        this.tweens.add({
          targets: this.hammerSprite,
          angle: -10,
          y: y + 10,
          alpha: 0,
          duration: 200,
          ease: 'Cubic.out'
        });
      }
    });
  }

  private setupToolSwitcher() {
    this.toolSwitcherContainer = this.add.container(0, 0).setDepth(30);
    this.root.add(this.toolSwitcherContainer);
    const createToolBtn = (x: number, y: number, key: string, tool: SmithingTool) => {
        const size = 110; 
        const bg = this.add.circle(0, 0, size/2, 0x1c1917, 0.9).setStrokeStyle(5, 0x57534e).setInteractive({ useHandCursor: true });
        const icon = this.add.image(0, 0, key).setDisplaySize(size * 0.65, size * 0.65);
        const container = this.add.container(x, y, [bg, icon]);
        bg.on('pointerdown', (p: any, lx: any, ly: any, event: any) => {
            event.stopPropagation();
            if (this.currentTool === tool && tool === 'HAMMER') {
                this.resetRing(); 
            } else {
                this.switchTool(tool);
            }
            this.tweens.add({ targets: container, scale: 0.85, duration: 80, yoyo: true });
        });
        return container;
    };
    this.hammerBtn = createToolBtn(0, 0, 'icon_hammer', 'HAMMER');
    this.tongsBtn = createToolBtn(125, 0, 'icon_tongs', 'TONGS'); 
    this.toolSwitcherContainer.add([this.hammerBtn, this.tongsBtn]);
  }

  private switchTool(tool: SmithingTool) {
    this.currentTool = tool;
    const hamBg = this.hammerBtn.list[0] as Phaser.GameObjects.Arc;
    const tonBg = this.tongsBtn.list[0] as Phaser.GameObjects.Arc;
    if (tool === 'HAMMER') {
        hamBg.setStrokeStyle(6, 0xfbbf24).setFillStyle(0x451a03, 1);
        tonBg.setStrokeStyle(4, 0x57534e).setFillStyle(0x1c1917, 0.9);
        if (this.manualControlsContainer) this.manualControlsContainer.setVisible(false);
        this.targetRing.setVisible(this.isPlaying);
        this.approachRing.setVisible(this.isPlaying);
        if (this.isPlaying) this.resetRing();
        this.targetOutlineGraphics.setVisible(false);
    } else {
        tonBg.setStrokeStyle(6, 0xfbbf24).setFillStyle(0x451a03, 1);
        hamBg.setStrokeStyle(4, 0x57534e).setFillStyle(0x1c1917, 0.9);
        if (this.manualControlsContainer) this.manualControlsContainer.setVisible(true);
        this.targetRing.setVisible(false);
        this.approachRing.setVisible(false);
        this.targetOutlineGraphics.setVisible(true);
        this.drawTargetGuidelineFixed();
    }
  }

  private setupManualControls() {
    this.manualControlsContainer = this.add.container(0, 0).setDepth(10);
    this.billetContainer.add(this.manualControlsContainer);
    const createBtn = (x: number, y: number, label: string, mode: 'X' | 'Y' | 'ROT') => {
        const size = 52;
        const isRot = mode === 'ROT';
        const bg = this.add.circle(0, 0, size/2, 0x1c1917, 0.8).setStrokeStyle(2, isRot ? 0x3b82f6 : 0xfbbf24, 0.8).setInteractive({ useHandCursor: true });
        const icon = this.add.text(0, 0, label, { fontSize: '24px', color: isRot ? '#60a5fa' : '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
        const btn = this.add.container(x, y, [bg, icon]);
        bg.on('pointerdown', (p: Phaser.Input.Pointer, lx: any, ly: any, event: any) => {
            event.stopPropagation();
